content.text:
/* Collapse double borders between cells */
table {
  border-collapse: collapse;
  width: 100%;
}

th, td {
  padding: 0.5rem 0.75rem;
  text-align: left;
  border: 1px solid #e5e7eb;
}

th {
  background: #f9fafb;
  font-weight: 600;
}

/* Alternating row colours for readability */
tbody tr:nth-child(even) {
  background: #f3f4f6;
}

/* Highlight the hovered row */
tbody tr:hover {
  background: #eff6ff;
}

/* Horizontal scroll wrapper */
.table-container {
  overflow-x: auto;
  -webkit-overflow-scrolling: touch; /* smooth scroll on iOS */
}

// data-table.component.ts
import { Component } from '@angular/core';

interface SaleRow {
  id: number;
  region: string;
  units: number;
  revenue: number;
  growth: string;
}

@Component({
  selector: 'app-data-table',
  standalone: true,
  template: `
    <div class="table-container">
      <table>
        <caption>Q1 2024 Sales</caption>
        <thead>
          <tr>
            @for (col of columnLabels; track col) {
              <th scope="col">{{ col }}</th>
            }
          </tr>
        </thead>
        <tbody>
          @for (row of rows; track row.id) {
            <tr>
              <th scope="row">{{ row.region }}</th>
              <td>{{ row.units | number }}</td>
              <td>{{ row.revenue | currency }}</td>
              <td>{{ row.growth }}</td>
            </tr>
          }
          @empty {
            <tr>
              <td [attr.colspan]="columnLabels.length" class="empty">
                No data available.
              </td>
            </tr>
          }
        </tbody>
      </table>
    </div>
  `,
})
export class DataTableComponent {
  columnLabels = ['Region', 'Units', 'Revenue', 'Growth'];

  rows: SaleRow[] = [
    { id: 1, region: 'North America', units: 12400, revenue: 248000, growth: '+8%' },
    { id: 2, region: 'Europe',        units: 9800,  revenue: 196000, growth: '+12%' },
    { id: 3, region: 'Asia Pacific',  units: 7600,  revenue: 152000, growth: '+18%' },
  ];
}

import { Component, computed, signal } from '@angular/core';

type SortDir = 'asc' | 'desc';

@Component({ /* ... */ })
export class SortableTableComponent {
  private _rows = signal<SaleRow[]>([
    { id: 1, region: 'North America', units: 12400, revenue: 248000, growth: '+8%' },
    { id: 2, region: 'Europe',        units: 9800,  revenue: 196000, growth: '+12%' },
  ]);

  sortKey   = signal<keyof SaleRow>('region');
  sortDir   = signal<SortDir>('asc');

  rows = computed(() => {
    const key = this.sortKey();
    const dir = this.sortDir();
    return [...this._rows()].sort((a, b) => {
      const cmp = a[key] < b[key] ? -1 : a[key] > b[key] ? 1 : 0;
      return dir === 'asc' ? cmp : -cmp;
    });
  });

  sort(key: keyof SaleRow) {
    if (this.sortKey() === key) {
      this.sortDir.update(d => d === 'asc' ? 'desc' : 'asc');
    } else {
      this.sortKey.set(key);
      this.sortDir.set('asc');
    }
  }
}

// data-table.component.spec.ts
import { TestBed, ComponentFixture } from '@angular/core/testing';
import { DataTableComponent } from './data-table.component';
import { By } from '@angular/platform-browser';

describe('DataTableComponent', () => {
  let fixture: ComponentFixture<DataTableComponent>;
  let component: DataTableComponent;

  beforeEach(async () => {
    await TestBed.configureTestingModule({
      imports: [DataTableComponent],
    }).compileComponents();
    fixture = TestBed.createComponent(DataTableComponent);
    component = fixture.componentInstance;
    fixture.detectChanges();
  });

  it('renders one body row per data item', () => {
    const rows = fixture.debugElement.queryAll(By.css('tbody tr'));
    expect(rows.length).toBe(component.rows.length);
  });

  it('renders the correct number of header cells', () => {
    const headers = fixture.debugElement.queryAll(By.css('thead th'));
    expect(headers.length).toBe(component.columnLabels.length);
  });

  it('shows empty state when rows is empty', () => {
    component.rows = [];
    fixture.detectChanges();
    const emptyCell = fixture.debugElement.query(By.css('td.empty'));
    expect(emptyCell).toBeTruthy();
    expect(emptyCell.nativeElement.textContent.trim()).toContain('No data available');
  });

  it('scopes column headers to col', () => {
    const ths = fixture.debugElement.queryAll(By.css('thead th'));
    ths.forEach(th => {
      expect(th.nativeElement.getAttribute('scope')).toBe('col');
    });
  });
});

