// paginated-table.component.ts
import { Component, computed, signal } from '@angular/core';
import { DecimalPipe } from '@angular/common';

@Component({
  selector: 'app-paginated-table',
  standalone: true,
  imports: [DecimalPipe],
  template: `
    <table>
      <caption>All Sales Rows — page {{ page() }} of {{ totalPages() }}</caption>
      <thead>
        <tr>
          <th scope="col">Region</th>
          <th scope="col">Units</th>
          <th scope="col">Revenue</th>
        </tr>
      </thead>
      <tbody>
        @for (row of pageRows(); track row.id) {
          <tr>
            <th scope="row">{{ row.region }}</th>
            <td>{{ row.units | number }}</td>
            <td>{{ row.revenue | currency }}</td>
          </tr>
        }
      </tbody>
    </table>

    <nav aria-label="Table pagination">
      <button (click)="prevPage()" [disabled]="page() === 1">Previous</button>
      <span>{{ page() }} / {{ totalPages() }}</span>
      <button (click)="nextPage()" [disabled]="page() === totalPages()">Next</button>
    </nav>
  `,
})
export class PaginatedTableComponent {
  readonly pageSize = 10;
  allRows = signal<SaleRow[]>(/* fetched from service */ []);
  page = signal(1);

  totalPages = computed(() =>
    Math.max(1, Math.ceil(this.allRows().length / this.pageSize))
  );

  pageRows = computed(() => {
    const start = (this.page() - 1) * this.pageSize;
    return this.allRows().slice(start, start + this.pageSize);
  });

  prevPage() { this.page.update(p => Math.max(1, p - 1)); }
  nextPage() { this.page.update(p => Math.min(this.totalPages(), p + 1)); }
}
